SELECT AVG(c.collision_value) AS average_collision_value
FROM collision_data c
INNER JOIN generations g ON c.generation_id = g.generation_id;

SELECT mean 
FROM generations 
WHERE generation_id = 1;

SELECT AVG(mean) AS average_mean_value
FROM generations
WHERE start_date > '2023-01-01' AND algorithm_name = 'Genetic Algorithm';

SELECT COUNT(*) AS total_collisions
FROM collision_data
WHERE collision_value > 1.0;

SELECT mean
FROM generations
ORDER BY mean DESC;

SELECT AVG(mean_collisions) AS average_collisions
FROM generations
WHERE start_date BETWEEN '2023-01-01' AND '2023-01-31';
